parameters.jsCode:
/**
 * Parse the LLM email JSON. Same defensive shape-walking as Hot outreach.
 * Carries the lead context forward by referencing the Sequence Config node.
 */
const lead = $('Sequence Config').item.json;
const ai = $input.item.json;

function extractContent(o) {
  if (Array.isArray(o.output) && o.output[0]?.content) {
    const block = o.output[0].content.find((c) => c.type === "output_text" || typeof c.text === "string");
    if (block?.text) return block.text;
  }
  if (typeof o.text === "string") return o.text;
  if (o.message?.content) return o.message.content;
  if (o.choices?.[0]?.message?.content) return o.choices[0].message.content;
  return "";
}

let raw = extractContent(ai).trim().replace(/^```(?:json)?\s*/i, "").replace(/```\s*$/, "").trim();
let parsed;
try { parsed = JSON.parse(raw); }
catch (e) { parsed = { subject: "Following up from Pemo", body: raw }; }

return {
  json: {
    ...lead,
    _outreach: {
      channel: "warm",
      step: "day_0",
      subject: parsed.subject || "Following up from Pemo",
      body: parsed.body || "",
      to: lead.email,
      generated_at: new Date().toISOString()
    }
  }
};

